```class Solution {
public:
    int removePalindromeSub(string s) {
        int steps = 0;
        for (int i = 0; i < s.length(); i++) {
            for (int j = i + 1; j < s.length(); j++) {
                if (s[i] == s[j] && isPalindrome(s.substr(i, j - i + 1))) {
                    s.erase(s.begin() + i);
                    steps++;
                    break;
                }
            }
        }
        return steps;
    }

    bool isPalindrome(string s) {
        int i = 0, j = s.length() - 1;
        while (i < j) {
            if (s[i] != s[j]) {
                break;
            }
            i++;
            j--;
        }
        return i == j;
    }
};
